    <div class="modal">
        <h2>💀 游戏结束</h2>
        <p>你的分数</p>
        <div class="final-score" id="finalScore">0</div>
        <p id="newHighScore" style="color: #e94560; display: none;">🎉 新纪录！</p>
        <p id="snakeLength">蛇身长度: 0</p>
        <button class="btn" id="restartBtn">再来一局</button>
